def _extract_positions(
    sampled_by_track: dict[int, list[dict[str, object]]],
) -> dict[str, Any]:
    """Extract foot-position data from sampled tracks for auto-zone suggestion.

    Returns a dict with frame dimensions and a list of position records,
    each with a dwell weight (higher = more stationary).
    """
    import math

    _STATIONARY_THRESHOLD = 20.0  # pixels — below this displacement = stationary

    positions: list[dict[str, Any]] = []
    frame_bounds = {"max_x": 0.0, "max_y": 0.0}

    def process_track(track_id: int, samples: list[dict[str, object]]) -> None:
        valid_samples = sorted(
            [s for s in samples if isinstance(s.get("pose"), dict)],
            key=lambda s: int(s.get("frame_idx", 0)),
        )

        movement_state = {"prev_x": None, "prev_y": None, "stationary_count": 1}

        for sample in valid_samples:
            pose_data = sample["pose"]
            bbox_coords = pose_data.get("bbox_xyxy")

            if bbox_coords is None:
                continue

            left, top, right, bottom = bbox_coords
            center_x = (left + right) / 2.0
            center_y = float(bottom)

            frame_bounds["max_x"] = max(frame_bounds["max_x"], center_x)
            frame_bounds["max_y"] = max(frame_bounds["max_y"], center_y)

            if movement_state["prev_x"] is not None:
                dx = center_x - movement_state["prev_x"]
                dy = center_y - movement_state["prev_y"]
                displacement = math.hypot(dx, dy)

                if displacement < _STATIONARY_THRESHOLD:
                    movement_state["stationary_count"] += 1
                else:
                    movement_state["stationary_count"] = 1
            else:
                movement_state["stationary_count"] = 1

            positions.append({
                "track_id": track_id,
                "frame_idx": int(sample.get("frame_idx", 0)),
                "x": round(center_x, 1),
                "y": round(center_y, 1),
                "dwell_frames": movement_state["stationary_count"],
            })

            movement_state["prev_x"] = center_x
            movement_state["prev_y"] = center_y

    for tid, track_samples in sampled_by_track.items():
        process_track(tid, track_samples)

    def estimate_dimension(value: float) -> int:
        return int(math.ceil(value / 16) * 16) if value > 0 else 0

    return {
        "frame_width": estimate_dimension(frame_bounds["max_x"]),
        "frame_height": estimate_dimension(frame_bounds["max_y"]),
        "positions": positions,
    }

def reduce_kinetics_label(
    raw_label: str,
    raw_score: float,
    *,
    min_raw_score: float = 0.20,
) -> ReducedPrediction:
    """
    Reduce a raw Kinetics-style label into a coarse retail label.

    Design:
    - Threshold low-confidence predictions to "unknown".
    - Use keyword / substring matching for coarse categorization.
    - Keep notes for debugging and later refinement.

    Args:
        raw_label: Model's top-1 label (e.g. "walking the dog")
        raw_score: Model's top-1 probability/score (0..1-ish)
        min_raw_score: If raw_score < this, return unknown.

    Returns:
        ReducedPrediction with a RetailLabel and confidence.
    """
    normalized_label = (raw_label or "").strip().lower()
    normalized_score = float(raw_score)

    # Early exit: empty label
    if not normalized_label:
        return ReducedPrediction("unknown", 0.0, "empty_raw_label")

    # Early exit: low confidence
    if normalized_score < min_raw_score:
        return ReducedPrediction(
            "unknown", normalized_score, f"low_raw_score:{normalized_score:.3f}"
        )

    # Rule 1: Pushing cart/wheelchair/stroller → moving
    is_push_motion = "pushing" in normalized_label and any(
        item in normalized_label for item in ("cart", "wheelchair", "stroller")
    )
    if is_push_motion:
        confidence = min(0.95, 0.55 + 0.9 * normalized_score)
        return ReducedPrediction(
            "moving", confidence, f"moving(push_cart)<-{raw_label}"
        )

    # Rule 2: Bend/crouch actions → bend
    if _contains_any(normalized_label, _BEND_HINTS):
        confidence = min(0.95, 0.55 + 0.8 * normalized_score)
        return ReducedPrediction("bend", confidence, f"bend<-{raw_label}")

    # Rule 3: Moving actions → moving
    if _contains_any(normalized_label, _MOVING_HINTS):
        confidence = min(0.95, 0.50 + 0.9 * normalized_score)
        return ReducedPrediction("moving", confidence, f"moving<-{raw_label}")

    # Rule 4: Idle actions → idle
    if _contains_any(normalized_label, _IDLE_HINTS):
        confidence = min(0.95, 0.50 + 0.9 * normalized_score)
        return ReducedPrediction("idle", confidence, f"idle<-{raw_label}")

    # Rule 5: Interaction actions → interaction
    if _contains_any(normalized_label, _INTERACTION_HINTS):
        confidence = min(0.95, 0.45 + 0.9 * normalized_score)
        return ReducedPrediction(
            "interaction", confidence, f"interaction<-{raw_label}"
        )

    # Fallback: no rule matched
    fallback_confidence = min(0.60, normalized_score)
    return ReducedPrediction(
        "unknown", fallback_confidence, f"no_rule_match<-{raw_label}"
    )

def _matches(journey: dict, filters: dict) -> bool:
    zones = set(journey.get("zone_sequence") or [])
    dwell = journey.get("zones_dwell_s") or {}
    actions = _track_actions(journey)
    seq = journey.get("zone_sequence") or []

    # Check zone visit filters
    for required_zones in [filters.get("visited_zones_all")]:
        if required_zones is not None and not set(required_zones) <= zones:
            return False

    for any_zones in [filters.get("visited_zones_any")]:
        if any_zones is not None and not set(any_zones) & zones:
            return False

    for excluded_zones in [filters.get("visited_zones_none")]:
        if excluded_zones is not None and set(excluded_zones) & zones:
            return False

    # Check action filters
    if "actions_any" in filters:
        if not any(actions.get(a) for a in filters["actions_any"]):
            return False

    if "actions_none" in filters:
        if any(actions.get(a) for a in filters["actions_none"]):
            return False

    # Check dwell time filter
    if "min_dwell_s" in filters:
        zone_constraint = filters["min_dwell_s"]
        zone_name = zone_constraint["zone"]
        min_seconds = float(zone_constraint["seconds"])
        actual_dwell = float(dwell.get(zone_name, 0.0))
        if actual_dwell < min_seconds:
            return False

    # Check total duration filters
    total_duration = float(journey.get("total_duration_s", 0.0))
    if "min_total_duration_s" in filters:
        if total_duration < float(filters["min_total_duration_s"]):
            return False

    if "max_total_duration_s" in filters:
        if total_duration > float(filters["max_total_duration_s"]):
            return False

    # Check conversion filter
    if "converted" in filters:
        if bool(journey.get("converted")) != filters["converted"]:
            return False

    # Check sequence filters
    if "zone_sequence_contains" in filters:
        pos = 0
        for wanted in filters["zone_sequence_contains"]:
            try:
                pos = seq.index(wanted, pos) + 1
            except ValueError:
                return False

    if "entered_first" in filters:
        if not seq or seq[0] != filters["entered_first"]:
            return False

    if "exited_last" in filters:
        if not seq or seq[-1] != filters["exited_last"]:
            return False

    # Check zone visit count filter
    if "min_zones_visited" in filters:
        if len(set(seq)) < float(filters["min_zones_visited"]):
            return False

    # Check action count filter
    if "min_action_count" in filters:
        action_constraint = filters["min_action_count"]
        action_name = action_constraint["action"]
        min_count = float(action_constraint["count"])
        actual_count = actions.get(action_name, 0)
        if actual_count < min_count:
            return False

    return True

