def _check_reaching(features: list[PoseFeatures]) -> PoseActionResult | None:
    """Reaching: wrist above shoulder or arm fully extended."""
    total_frames = len(features)
    if total_frames == 0:
        return None

    wrist_above_count = 0
    arm_extended_count = 0

    for pose_frame in features:
        # Check if either wrist is positioned above shoulder
        for wrist_height in [pose_frame.left_wrist_height, pose_frame.right_wrist_height]:
            if wrist_height is not None and wrist_height < _WRIST_ABOVE_SHOULDER:
                wrist_above_count += 1

        # Check if either arm is fully extended with wide shoulder angle
        for elbow_angle, shoulder_angle in [
            (pose_frame.left_elbow_angle, pose_frame.left_shoulder_angle),
            (pose_frame.right_elbow_angle, pose_frame.right_shoulder_angle),
        ]:
            if (elbow_angle is not None and elbow_angle > _ELBOW_EXTENDED and
                shoulder_angle is not None and shoulder_angle > 60):
                arm_extended_count += 1

    total_wrist_observations = 2 * total_frames
    wrist_fraction = wrist_above_count / total_wrist_observations
    extended_fraction = arm_extended_count / total_wrist_observations

    # Priority: wrist above shoulder detection
    if wrist_fraction > 0.2:
        confidence = min(0.9, 0.5 + wrist_fraction)
        return PoseActionResult("reaching", confidence, f"above_frac={wrist_fraction:.2f}")

    # Secondary: arm fully extended detection
    if extended_fraction > 0.25:
        confidence = min(0.85, 0.45 + extended_fraction)
        return PoseActionResult("reaching", confidence, f"extended_frac={extended_fraction:.2f}")

    return None

def _sorted_samples(
    samples: list[dict[str, object]],
    *,
    target_fps: float,
) -> list[dict[str, object]]:
    fps = 30.0 if target_fps <= 0 else float(target_fps)
    result = []

    for sample in samples:
        if not isinstance(sample, dict):
            continue

        frame_idx_key = "frame_idx"
        if frame_idx_key not in sample:
            continue

        try:
            frame_number = int(sample[frame_idx_key])
        except (ValueError, TypeError, KeyError):
            continue

        zone_data = sample.get("aisles") or sample.get("zones") or []
        zone_strings = [str(zone) for zone in zone_data] if isinstance(zone_data, list) else []

        time_seconds = frame_number / fps
        result.append({
            "frame_idx": frame_number,
            "t_s": time_seconds,
            "zones": zone_strings,
        })

    result.sort(key=lambda entry: int(entry["frame_idx"]))
    return result

def _reduce_from_topk(
    labels: Sequence[str],
    scores: Sequence[float],
    *,
    min_raw_score: float,
) -> ReducedPrediction:
    """
    Prefer the first top-k label that maps to a non-unknown retail bucket.
    Falls back to top-1 with min_raw_score thresholding.
    """
    # Try each label in rank order with lenient scoring to find interpretable result
    for label, score in zip(labels, scores):
        result = reduce_kinetics_label(label, float(score), min_raw_score=0.0)
        if result.retail_label != "unknown":
            return result

    # No interpretable label found in top-k; use top-1 with strict threshold
    if labels and scores:
        top_label = labels[0]
        top_score = float(scores[0])
        return reduce_kinetics_label(top_label, top_score, min_raw_score=min_raw_score)

    # Handle empty input gracefully
    return ReducedPrediction("unknown", 0.0, "empty_topk")

def _check_browsing(
    temporal: TemporalFeatures,
    zones: Sequence[str],
    walkway_zones: set[str],
) -> PoseActionResult | None:
    """Browsing: stationary in a non-walkway zone."""
    velocity = temporal.com_velocity

    if velocity > _COM_WALK_THRESHOLD:
        return None

    non_walkway_zones = [zone for zone in zones if zone not in walkway_zones]
    if len(non_walkway_zones) == 0:
        return None

    normalized_velocity = min(velocity / _COM_WALK_THRESHOLD, 1.0)
    stillness_score = 1.0 - normalized_velocity
    confidence = min(0.8, 0.45 + stillness_score * 0.3)

    return PoseActionResult(
        "browsing",
        confidence,
        f"zones={non_walkway_zones} com_vel={velocity:.4f}",
    )
